@startuml
title Dubbo 获取zk注册中心实例

participant RegistryProtocol
participant AbstractRegistryFactory
participant ZookeeperRegistryFactory

RegistryProtocol -> AbstractRegistryFactory : [01] registryFactory.getRegistry(registryUrl)
AbstractRegistryFactory -> ZookeeperRegistryFactory : [02] registry = createRegistry(url);
ZookeeperRegistryFactory --> RegistryProtocol : [03] new ZookeeperRegistry(url, zookeeperTransporter);

@enduml
